/// <summary>
/// Extension class of <c>VendInvoiceDocumentDP</c> for text block management
/// </summary>
[ExtensionOf(classStr(VendInvoiceDocumentDP))]
final class FWFTextBlockVendInvoiceDocumentDP_Extension
{
}

Method.Source:
public void insertVendInvoiceDocumentTmp(NoYes _purchInvoiceTransOrTaxTrans, NoYes _vendPaymSched)
{
    next insertVendInvoiceDocumentTmp(_purchInvoiceTransOrTaxTrans, _vendPaymSched);

    VendInvoiceDocumentTmp vendInvoiceDocumentTmpLocal = this.vendInvoiceDocumentTmp;
    vendInvoiceDocumentTmpLocal.FWFTextBlockHeaderText = '';
    vendInvoiceDocumentTmpLocal.FWFTextBlockFooterText = '';
    vendInvoiceDocumentTmpLocal.FWFTextBlockHeaderTextLine = '';
    vendInvoiceDocumentTmpLocal.FWFTextBlockFooterTextLine = '';
    vendInvoiceDocumentTmpLocal.update();

    if (isFirstRecord)
    {
        FWFTextBlockReportTextInit::newParameters(this.vendInvoiceDocumentTmp, this.vendInvoiceJour).addTexts();
    }

    if (!this.vendInvoiceDocumentTmp.TaxCode)
    {
        if (this.vendInvoiceDocumentTmp.ItemId || this.vendInvoiceTrans.isCategoryBased())
        {
            FWFTextBlockReportTextInit::newParameters(this.vendInvoiceDocumentTmp, this.vendInvoiceTrans).addLineTexts();
        }
    }
}
